// Pre-state is unique and well-formed, so the pre-view has no duplicates.
// Inject that structural fact so z3 has a handle on `pre_self_@.push(new_value)`.
pre_self_.unique_implys_no_duplicates();

// The function ensures has the shape `H ==> det_push_equal(r1, r2, post1_, post2_)`
// where H is the synthesised conjunction of both runs' ensures. The post1_/post2_
// ensures-conjuncts are NOT free facts in the proof context -- they are only
// available as hypotheses under the antecedent of the implication. Bring H into
// scope with `if H { ... }` (the same pattern that closes the set_owning_container
// det check) so the alignment facts z3 needs become available inside the branch.
if post1_self_.wf()
    && (post1_self_@ == pre_self_@.push(new_value))
    && (post1_self_.len() == pre_self_.len() + 1)
    && (forall|v: T| #![auto]
            pre_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v))
    && (post1_self_.get_node_ref(new_value) == r1)
    && post1_self_.unique()
    && post2_self_.wf()
    && (post2_self_@ == pre_self_@.push(new_value))
    && (post2_self_.len() == pre_self_.len() + 1)
    && (forall|v: T| #![auto]
            pre_self_@.contains(v) ==>
                pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v))
    && (post2_self_.get_node_ref(new_value) == r2)
    && post2_self_.unique()
{
    // Both post-states are well-formed and unique; surface no-duplicates on both
    // post-views so z3 has a structural handle on the augmented sequence.
    post1_self_.unique_implys_no_duplicates();
    post2_self_.unique_implys_no_duplicates();

    // Both post-views are pinned to `pre_self_@.push(new_value)` -- chain that
    // equality through the common middle term and lift to Seq extensionality so
    // z3 sees a single shared spec_seq across the two runs.
    assert(post1_self_@ == pre_self_@.push(new_value));
    assert(post2_self_@ == pre_self_@.push(new_value));
    assert(post1_self_@ =~= post2_self_@);
    assert(post1_self_@ == post2_self_@);

    // Lengths are pinned to pre_self_.len() + 1 in both runs.
    assert(post1_self_.len() == pre_self_.len() + 1);
    assert(post2_self_.len() == pre_self_.len() + 1);
    assert(post1_self_.len() == post2_self_.len());

    // Pointwise agreement of get_node_ref on every value already present in
    // pre_self_@: chain the two `forall|v|` ensures on the shared term
    // `pre_self_.get_node_ref(v)`. The explicit trigger annotation suppresses
    // the low-confidence auto-pick warning Verus emitted on the prior attempt.
    assert forall|v: T|
        #![trigger post1_self_.get_node_ref(v), post2_self_.get_node_ref(v)]
        pre_self_@.contains(v) implies
            post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v)
    by {
        // Both post1_self_.get_node_ref(v) and post2_self_.get_node_ref(v)
        // equal pre_self_.get_node_ref(v) by the respective forall ensures,
        // so z3 chains them by transitivity through that shared middle term.
    };

    // r1 / r2 are pinned to post1_/post2_.get_node_ref(new_value) -- surface
    // those equalities so z3 has direct handles on the candidate results
    // rather than only the uninterpreted get_node_ref applications.
    assert(r1 == post1_self_.get_node_ref(new_value));
    assert(r2 == post2_self_.get_node_ref(new_value));
}
